// Ce nœud synchronise les variables globales avec enrichedVars.
// Il met à jour enrichedVars avec les variables globales actuelles
// et s'assure que chaque variable suit la nouvelle structure définie.
// Les variables sont stockées dans deux types de stockage : "default" et "file".
// Les variables sont structurées avec des propriétés comme nomVarG, typeVarG, instances, detailEtat, etc.
// La fonction gère également la restauration des variables globales manquantes depuis enrichedVars.
// Elle prend en compte les instances et les sous-variables pour une synchronisation cohérente.

func:
// 🔄 Fonction utilitaire pour les valeurs par défaut selon le type
function defaultForType(type) {
    switch (type) {
        case "boolean": return false;
        case "int": case "number": return 0;
        case "array": return [];
        case "object": return {};
        case "date": return new Date().toISOString().slice(0, 10);
        default: return "";
    }
}

const storeDefault = "default";
const storeFile = "file";
const allKeys = global.keys(storeDefault) || [];
let enrichedVars = global.get("enrichedVars", storeFile) || {};

// 🔄 Conversion utile : typé → string/JSON
function convertToString(value, type) {
    if (value === null || value === undefined) return "";
    try {
        switch (type) {
            case "array":
            case "object":
                return JSON.stringify(value);
            case "boolean":
                return value ? "true" : "false";
            case "date":
                return new Date(value).toISOString();
            default:
                return String(value);
        }
    } catch (err) {
        return String(value);
    }
}

// ⏺️ Export des variables en enrichedVars
allKeys.forEach(key => {
    if (key === "enrichedVars") return;
    const val = global.get(key, storeDefault);
    const type = typeof val;

    // Cas des objets avec instances
    if (type === "object" && val && !Array.isArray(val)) {
        const instances = Object.keys(val);
        if (instances.length === 0) return;

        const firstInstance = val[instances[0]];
        if (typeof firstInstance === "object") {
            const props = Object.keys(firstInstance);
            const propDefs = props.map(p => {
                const v = firstInstance[p];
                const t = Array.isArray(v) ? "array" : typeof v;
                const prop = { nom: p, type: t };
                if (t === "object") prop.schema = {};  // Initialisation du schéma
                return prop;
            });

            let valeurs = {};
            instances.forEach(inst => {
                valeurs[inst] = {};
                propDefs.forEach(({ nom, type }) => {
                    const v = val[inst]?.[nom];
                    valeurs[inst][nom] = (type === "object" || type === "array")
                        ? JSON.stringify(v)
                        : convertToString(v, type);
                });
            });

            enrichedVars[key] = {
                nomVarG: key,
                abbrVarG: val._abbrVarG || "",
                typeVarG: "object",
                instances,
                descriptionVarG: "Auto-export",
                dateUpdateVarG: new Date().toISOString(),
                indexInstances: instances.map((_, idx) => String(idx)).join(","),
                proprietesByInstance: {
                    proprietes: propDefs,
                    valeurs,
                    abbrProprietes: val._abbrProprietes || {}
                }
            };
        } else {
            // Cas simple
            enrichedVars[key] = {
                nomVarG: key,
                abbrVarG: val._abbrVarG || "",
                typeVarG: "object",
                instances: ["*"],
                descriptionVarG: "Auto-export",
                dateUpdateVarG: new Date().toISOString(),
                indexInstances: "0",
                proprietesByInstance: {
                    proprietes: [{ nom: "*", type }],
                    valeurs: {
                        "*": {
                            "*": convertToString(val, type)
                        }
                    },
                    abbrProprietes: val._abbrProprietes || {}
                }
            };
        }
    } else {
        // Cas simple (non objet ou tableau)
        enrichedVars[key] = {
            nomVarG: key,
            abbrVarG: val._abbrVarG || "",
            typeVarG: type,
            instances: ["*"],
            descriptionVarG: "Auto-export",
            dateUpdateVarG: new Date().toISOString(),
            indexInstances: "0",
            proprietesByInstance: {
                proprietes: [{ nom: "*", type }],
                valeurs: {
                    "*": {
                        "*": convertToString(val, type)
                    }
                },
                abbrProprietes: val._abbrProprietes || {}
            }
        };
    }
});

// 💾 Sauvegarde dans storeFile
global.set("enrichedVars", enrichedVars, storeFile);
msg.payload = enrichedVars;
msg.info = "💾 Sauvegarde vers enrichedVars (file) terminée.";
return msg;

if (msg.payload === "confirm_clicked") {
  const varSelected = flow.get("varSelected");
  if (!varSelected) {
    msg.info = "⚠️ Rien à supprimer.";
    return msg;
  }
  let enrichedVars = global.get("enrichedVars", "file") || {};
  delete enrichedVars[varSelected];
  delete enrichedVars[""];//supprime var fantome
  global.set("enrichedVars", enrichedVars, "file");
  global.set(varSelected, undefined, "default");
  flow.set("varSelected", "none");
  msg.payload = "none";
  msg.info = `✅ Variable "${varSelected}" supprimée.`;
}
return msg;

let enrichedVars = global.get("enrichedVars", "file") || {};
let varSelected = flow.get("varSelected") || null;
let formData = msg.payload;

if (!formData || !formData.nomVarG) {
    msg.info = "❌ Formulaire incomplet ou variable non spécifiée.";
    return null; // sécurité
}

let oldName = varSelected;   // ancien nom suivi
let newName = formData.nomVarG.trim();

// --- Cas création ---
if (!enrichedVars[oldName]) {
    if (enrichedVars[newName]) {
        // 🚨 Collision lors de la création
        msg.error = `❌ Impossible de créer '${newName}', une variable existe déjà avec ce nom.`;
        return msg;
    }

    // Générer indexInstances automatiquement si absent
    let indexInstances = [];
    if (formData.instances) {
        indexInstances = formData.instances.split(',').map((e, idx) => String(idx));
    }

    // Création de la nouvelle variable
    enrichedVars[newName] = {
        nomVarG: newName,
        abbrVarG: formData.abbrVarG || "",
        typeVarG: formData.typeVarG || "",
        instances: formData.instances ? formData.instances.split(',').map(e => e.trim()) : [],
        indexInstances: indexInstances,
        descriptionVarG: formData.descriptionVarG || "",
        dateUpdateVarG: new Date().toISOString(),
        proprietesByInstance: {
            proprietes: [],
            valeurs: {},
            abbrProprietes: {}
        }
    };

    flow.set("varSelected", newName);
    global.set("enrichedVars", enrichedVars, "file");

    msg.payload = newName;
    msg.info = `✅ Nouvelle variable créée : ${newName}`;
    return msg;
}

// --- Cas modification ---
let current = enrichedVars[oldName];

// ⚠️ Si le nom a changé
if (oldName !== newName) {
    if (enrichedVars[newName]) {
        // 🚨 Collision lors du renommage
        msg.error = `⚠️ Attention : '${newName}' existe déjà. Veux-tu vraiment remplacer '${oldName}' par '${newName}' ?`;
        msg.confirmRename = { from: oldName, to: newName };
        return msg;
    }

    // Renommage → déplacement de la clé
    enrichedVars[newName] = current;
    delete enrichedVars[oldName];
}

// Mise à jour des infos
let target = enrichedVars[newName];
target.nomVarG = newName;
target.abbrVarG = formData.abbrVarG || "";
target.descriptionVarG = formData.descriptionVarG || "";
target.typeVarG = formData.typeVarG || "";
target.instances = formData.instances ? formData.instances.split(',').map(e => e.trim()) : [];
// Générer indexInstances automatiquement si absent ou incohérent
target.indexInstances = target.instances.map((_, idx) => String(idx));
target.dateUpdateVarG = new Date().toISOString();

// Assurer que abbrProprietes existe
if (!target.proprietesByInstance) {
    target.proprietesByInstance = { proprietes: [], valeurs: {}, abbrProprietes: {} };
} else if (!target.proprietesByInstance.abbrProprietes) {
    target.proprietesByInstance.abbrProprietes = {};
}

// Sauvegardes
flow.set("varSelected", newName);
global.set("enrichedVars", enrichedVars, "file");

// Retour
msg.payload = newName;
msg.info = (oldName !== newName)
    ? `⚠️ Nom modifié : '${oldName}' → '${newName}'`
    : `✅ Infos mises à jour pour : ${newName}`;
return msg;

// Build → données template
// Désérialise les objets/tableaux, initialise les schémas, prépare les données pour le template
let enrichedVars = global.get("enrichedVars", "file") || {};
let varName = flow.get("varSelected") || msg.payload || null;
let variable = varName ? enrichedVars[varName] : null;

if (!variable) {
    msg.info = "Variable non trouvée pour l'éditeur de propriétés.";
    msg.payload = null;
    return msg;
}

// Helpers
const toArray = (v) => Array.isArray(v) ? v : (typeof v === "string" && v.trim() ? v.split(",").map(x => x.trim()) : []);
const deepClone = (o) => JSON.parse(JSON.stringify(o || {}));
const defaultForType = (t) => {
    switch (t) {
        case "boolean": return false;
        case "int": case "number": return 0;
        case "array": return [];
        case "object": return {};
        case "date": return new Date().toISOString().slice(0, 10);
        default: return "";
    }
};

// Instances → toujours un tableau
let instances = toArray(variable.instances || ["*"]);

// Propriétés → nettoyage et validation
let propArr = (variable.proprietesByInstance?.proprietes || [])
    .filter(p => p && typeof p.nom === "string" && typeof p.type === "string")
    .map(p => {
        const prop = {
            nom: String(p.nom),
            type: String(p.type),
            schema: p.schema || (p.type === "object" ? {} : undefined)
        };
        // Assurez-vous que le schéma est toujours un objet
        if (prop.type === "object" && !prop.schema) {
            prop.schema = {};
        }
        return prop;
    });

// Abréviations des propriétés
let abbrMap = deepClone(variable.proprietesByInstance?.abbrProprietes || {});

// Valeurs → désérialisation des objets/tableaux
let valeursRaw = deepClone(variable.proprietesByInstance?.valeurs || {});
let valeurs = {};
instances.forEach(inst => {
    valeurs[inst] = {};
    propArr.forEach(p => {
        const storedValue = valeursRaw[inst]?.[p.nom];
        let value = storedValue;
        try {
            if (p.type === "object" && typeof storedValue === "string") {
                value = JSON.parse(storedValue);  // Désérialisation des objets
            } else if (p.type === "array" && typeof storedValue === "string") {
                value = JSON.parse(storedValue);  // Désérialisation des tableaux
            } else if (p.type === "boolean") {
                value = storedValue === true || storedValue === "true";
            } else if (p.type === "int" || p.type === "number") {
                value = parseFloat(storedValue) || 0;
            }
        } catch (e) {
            console.warn(`Désérialisation échouée pour ${p.nom}:`, e);
            value = defaultForType(p.type);
        }
        valeurs[inst][p.nom] = value !== undefined ? value : defaultForType(p.type);
    });
});

// Payload pour le template
msg.payload = {
    nomVarG: variable.nomVarG || varName,
    abbrVarG: variable.abbrVarG || "",
    typeVarG: variable.typeVarG || "",
    instances,
    proprietesByInstance: {
        proprietes: propArr,
        abbrProprietes: abbrMap,
        valeurs
    },
    descriptionVarG: variable.descriptionVarG || "",
    dateUpdateVarG: variable.dateUpdateVarG || new Date().toISOString()
};
msg.info = "✅ Données préparées pour le template.";
return msg;

/// 💾 Save changes to enrichedVars
const storeFile = "file";
let enrichedVars = global.get("enrichedVars", storeFile) || {};
let formData = msg.payload || {};

if (!formData || !formData.nomVarG) {
    msg.info = "❌ Données invalides reçues depuis le template.";
    return null;
}

const varName = String(formData.nomVarG).trim();

// Helpers
const toArray = (v) => {
    if (Array.isArray(v)) return v;
    if (typeof v === "string") {
        const s = v.trim();
        if (!s) return [];
        return s.includes(",") ? s.split(",").map(x => x.trim()).filter(Boolean) : [s];
    }
    return [];
};
const deepClone = (o) => JSON.parse(JSON.stringify(o || {}));

// Instances et indexInstances
let instances = toArray(formData.instances);
const indexInstances = instances.map((_, i) => String(i));

// Récupération de proprietesByInstance depuis formData
const rawPBI = formData.proprietesByInstance || {};

// Filtrer/normaliser les propriétés
let props = (Array.isArray(rawPBI.proprietes) ? rawPBI.proprietes : [])
    .filter(p => p && typeof p.nom === "string" && typeof p.type === "string" && p.nom.trim() !== "")
    .map(p => ({
        nom: String(p.nom).trim(),
        type: String(p.type).trim(),
        schema: p.schema  // Conserver le schéma
    }));

// abbrProprietes doit rester un objet clé=nomPropriété → abréviation
let abbrMap = {};
if (rawPBI.abbrProprietes && typeof rawPBI.abbrProprietes === "object" && !Array.isArray(rawPBI.abbrProprietes)) {
    abbrMap = deepClone(rawPBI.abbrProprietes);
}

// Purger les abbr des propriétés qui n'existent plus
Object.keys(abbrMap).forEach(k => {
    if (!props.find(p => p.nom === k)) delete abbrMap[k];
});

// Valeurs: garder uniquement pour les propriétés présentes + sérialisation
let valeurs = {};
instances.forEach(inst => {
    valeurs[inst] = {};
    props.forEach(({ nom, type }) => {
        const v = rawPBI.valeurs?.[inst]?.[nom];
        if (type === 'object' || type === 'array') {
            valeurs[inst][nom] = v ? JSON.stringify(v) : (type === 'object' ? '{}' : '[]');
        } else {
            valeurs[inst][nom] = v;
        }
    });
});

// Construire l'objet final
let current = enrichedVars[varName] || {};
enrichedVars[varName] = {
    nomVarG: varName,
    abbrVarG: current.abbrVarG || "",
    typeVarG: formData.typeVarG || current.typeVarG || "",
    instances,
    indexInstances,
    descriptionVarG: current.descriptionVarG || "",
    dateUpdateVarG: new Date().toISOString(),
    proprietesByInstance: {
        proprietes: props,
        abbrProprietes: abbrMap,
        valeurs
    }
};

// Sauvegarde
global.set("enrichedVars", enrichedVars, storeFile);
msg.payload = enrichedVars[varName];
msg.info = `💾 Propriétés sauvegardées pour '${varName}' (${props.length} propriétés, ${instances.length} instance(s)).`;
return msg;

//recharger l'original des propriétés et instances de la variables
let nomVarG=msg.payload;
flow.set("varSelected", nomVarG);
msg.topic="annuler";
msg.info= "Annulation des modifications sur les valeurs de $nomVarG";
// Modifications enregistrées pour ${data.nomVarG}
return msg;
